class Solution {
public:
    vector<string> ans;
    vector<vector<int>> visited;

    bool isValid(int x, int y, int n, vector<vector<int>>& grid) {
        return (x >= 0 && x < n && y >= 0 && y < n &&
                grid[x][y] == 1 && visited[x][y] == 0);
    }

    void dfs(int x, int y, int n, vector<vector<int>>& grid, string path) {
        if (x == n - 1 && y == n - 1) {
            ans.push_back(path);
            return;
        }

        visited[x][y] = 1;

        if (isValid(x + 1, y, n, grid))
            dfs(x + 1, y, n, grid, path + 'D');

        if (isValid(x, y - 1, n, grid))
            dfs(x, y - 1, n, grid, path + 'L');

        if (isValid(x, y + 1, n, grid))
            dfs(x, y + 1, n, grid, path + 'R');

        if (isValid(x - 1, y, n, grid))
            dfs(x - 1, y, n, grid, path + 'U');

        visited[x][y] = 0;
    }

    vector<string> findAllPaths(int n, vector<vector<int>>& grid) {
        ans.clear();

        if (grid[0][0] == 0) return {};

        visited.assign(n, vector<int>(n, 0));

        dfs(0, 0, n, grid, "");
        return ans;
    }
};

