#define MAXN 10
#define MAXPATHS 10000   // MUST be large enough
#define MAXLEN 100       // MUST be >= max possible path length

int visited[MAXN][MAXN];
char paths[MAXPATHS][MAXLEN];
int pathCount;

int isValid(int x, int y, int n, int grid[MAXN][MAXN]) {
    return (x >= 0 && x < n &&
            y >= 0 && y < n &&
            grid[x][y] == 1 &&
            visited[x][y] == 0);
}

void dfs(int x, int y, int n, int grid[MAXN][MAXN], char *path) {
    // STOP if paths array is full
    if (pathCount >= MAXPATHS)
        return;

    if (x == n - 1 && y == n - 1) {
        strcpy(paths[pathCount++], path);
        return;
    }

    visited[x][y] = 1;

    int len = strlen(path);

    // STOP if path buffer is full
    if (len >= MAXLEN - 1) {
        visited[x][y] = 0;
        return;
    }

    // Down
    if (isValid(x + 1, y, n, grid)) {
        path[len] = 'D';
        path[len + 1] = '\0';
        dfs(x + 1, y, n, grid, path);
        path[len] = '\0';
    }

    // Left
    if (isValid(x, y - 1, n, grid)) {
        path[len] = 'L';
        path[len + 1] = '\0';
        dfs(x, y - 1, n, grid, path);
        path[len] = '\0';
    }

    // Right
    if (isValid(x, y + 1, n, grid)) {
        path[len] = 'R';
        path[len + 1] = '\0';
        dfs(x, y + 1, n, grid, path);
        path[len] = '\0';
    }

    // Up
    if (isValid(x - 1, y, n, grid)) {
        path[len] = 'U';
        path[len + 1] = '\0';
        dfs(x - 1, y, n, grid, path);
        path[len] = '\0';
    }

    visited[x][y] = 0; // backtrack
}

int compareStrings(const void *a, const void *b) {
    return strcmp((char *)a, (char *)b);
}

char **findAllPaths(int n, int grid[MAXN][MAXN], int *returnSize) {
    memset(visited, 0, sizeof(visited));
    pathCount = 0;

    if (grid[0][0] == 0) {
        *returnSize = 0;
        return NULL;
    }

    char path[MAXLEN] = "";
    dfs(0, 0, n, grid, path);

    *returnSize = pathCount;

    if (pathCount == 0)
        return NULL;

    qsort(paths, pathCount, sizeof(paths[0]), compareStrings);

    char **result = malloc(pathCount * sizeof(char *));
    for (int i = 0; i < pathCount; i++) {
        result[i] = strdup(paths[i]);
    }

    return result;
}

