class Solution {

    private List<String> paths;
    private int[][] visited;

    private boolean isValid(int x, int y, int n, int[][] grid) {
        return x >= 0 && x < n && y >= 0 && y < n &&
               grid[x][y] == 1 && visited[x][y] == 0;
    }

    private void dfs(int x, int y, int n, int[][] grid, String path) {
        if (x == n - 1 && y == n - 1) {
            paths.add(path);
            return;
        }

        visited[x][y] = 1;

        // Down
        if (isValid(x + 1, y, n, grid))
            dfs(x + 1, y, n, grid, path + "D");

        // Left
        if (isValid(x, y - 1, n, grid))
            dfs(x, y - 1, n, grid, path + "L");

        // Right
        if (isValid(x, y + 1, n, grid))
            dfs(x, y + 1, n, grid, path + "R");

        // Up
        if (isValid(x - 1, y, n, grid))
            dfs(x - 1, y, n, grid, path + "U");

        visited[x][y] = 0; // backtrack
    }

    public List<String> findAllPaths(int n, int[][] grid) {
        paths = new ArrayList<>();

        if (grid[0][0] == 0)
            return paths;

        visited = new int[n][n];
        dfs(0, 0, n, grid, "");

        return paths;
    }
}

