class Solution {
    constructor() {
        this.paths = [];
        this.visited = [];
    }

    isValid(x, y, n, grid) {
        return (
            x >= 0 && x < n &&
            y >= 0 && y < n &&
            grid[x][y] === 1 &&
            this.visited[x][y] === 0
        );
    }

    dfs(x, y, n, grid, path) {
        if (x === n - 1 && y === n - 1) {
            this.paths.push(path);
            return;
        }

        this.visited[x][y] = 1;

        // Down
        if (this.isValid(x + 1, y, n, grid)) {
            this.dfs(x + 1, y, n, grid, path + "D");
        }

        // Left
        if (this.isValid(x, y - 1, n, grid)) {
            this.dfs(x, y - 1, n, grid, path + "L");
        }

        // Right
        if (this.isValid(x, y + 1, n, grid)) {
            this.dfs(x, y + 1, n, grid, path + "R");
        }

        // Up
        if (this.isValid(x - 1, y, n, grid)) {
            this.dfs(x - 1, y, n, grid, path + "U");
        }

        this.visited[x][y] = 0; // backtrack
    }

    findAllPaths(n, grid) {
        this.paths = [];

        if (grid[0][0] === 0) return [];

        this.visited = Array.from({ length: n }, () => Array(n).fill(0));

        this.dfs(0, 0, n, grid, "");

        return this.paths;
    }
}
